invalidCreditGiftCard.query:
#graphql
  mutation GiftCardCreditPayloadGiftCardRejected($id: ID!, $input: GiftCardCreditInput!) {
    giftCardCredit(id: $id, creditInput: $input) {
      giftCardCreditTransaction {
        id
      }
      giftCard {
        id
        balance {
